from langchain_core.tools import tool


@tool
def get_weather(city: str) -> str:
    """Return current weather for a city."""
    return f"Sunny, 22°C in {city}"


@tool
def calculate(expression: str) -> float:
    """Evaluate a mathematical expression safely."""
    # In production: use a proper expression parser
    return eval(expression, {"__builtins__": {}})  # noqa: S307


llm_with_tools = ChatAnthropic(model="claude-haiku-4-5-20251001").bind_tools(
    [get_weather, calculate]
)

response = llm_with_tools.invoke([HumanMessage(content="What's the weather in Tokyo?")])

if response.tool_calls:
    for call in response.tool_calls:
        print(f"Tool: {call['name']}")
        print(f"Args: {call['args']}")
        # Execute the tool and pass result back
        result = get_weather.invoke(call["args"])
        tool_msg = ToolMessage(content=result, tool_call_id=call["id"])
        final = llm_with_tools.invoke(
            [HumanMessage(content="What's the weather in Tokyo?"), response, tool_msg]
        )
        print(final.content)
